// Traverse a single tree and return the leaf value
static inline float xgb_predict_tree(int tree_idx, const float* features) {
  int offset = xgb_tree_offset[tree_idx];
  int node = 0;
  while (xgb_feature[offset + node] >= 0) {
    if (features[xgb_feature[offset + node]] < xgb_threshold[offset + node]) {
      node = xgb_left[offset + node];
    } else {
      node = xgb_right[offset + node];
    }
  }
  return xgb_value[offset + node];
}

static inline void xgb_softmax(float* values, int n) {
  float max_val = values[0];
  for (int i = 1; i < n; i++) {
    if (values[i] > max_val) max_val = values[i];
  }
  float sum = 0.0f;
  for (int i = 0; i < n; i++) {
    values[i] = expf(values[i] - max_val);
    sum += values[i];
  }
  for (int i = 0; i < n; i++) {
    values[i] /= sum;
  }
}

// Run XGBoost inference. Outputs probabilities for each class.
// features: array of 9 scaled floats
// output: array of 3 floats (ADL_prob, PreFall_prob, Fall_prob)
static void xgb_predict(const float* features, float* output) {
  // Initialize class scores with base_score
  for (int c = 0; c < XGB_NUM_CLASSES; c++) {
    output[c] = 0.0f;
  }

  // Sum leaf values for each class
  // Trees are interleaved: tree 0→class 0, tree 1→class 1, tree 2→class 2,
  //                        tree 3→class 0, tree 4→class 1, ...
  for (int t = 0; t < XGB_NUM_TREES; t++) {
    int class_idx = t % XGB_NUM_CLASSES;
    output[class_idx] += xgb_predict_tree(t, features);
  }

  // Apply softmax to get probabilities
  xgb_softmax(output, XGB_NUM_CLASSES);
}

// Returns the predicted class: 0=ADL, 1=Pre-Fall, 2=Fall
static int xgb_predict_class(const float* features) {
  float proba[XGB_NUM_CLASSES];
  xgb_predict(features, proba);
  int best = 0;
  for (int i = 1; i < XGB_NUM_CLASSES; i++) {
    if (proba[i] > proba[best]) best = i;
  }
  return best;
}

